"use strict";$(function(){$(".page-diy-section .object-lists").on("click",'.btn-object[data-type="member"]',function(){var t=$(this).data("type");if(0!=$(this).data("open")){var e=$('[data-object-type="'+t+'"]').html();console.log(t),$(".preview-target").append(e);$(".preview-target .object-item").each(function(t){var e=$(this).data("type");$(this).attr("data-object-index",e+"-"+t),e+"-"+t})}else toast.error("该组件完善中...","danger")})});